// Time:  O(n)
// Space: O(w)

class Solution {
public:
    vector<string> spellchecker(vector<string>& wordlist, vector<string>& queries) {
        unordered_set<string> words(wordlist.cbegin(), wordlist.cend());
        unordered_map<string, string> caps, vows;
        for (const auto& word : wordlist) {
            const auto& lower = tolow(word);
            caps.emplace(lower, word);
            vows.emplace(todev(lower), word);
        }

        for (auto& query : queries) {
            if (words.count(query)) {
                continue;
            }
            const auto& lower = tolow(query);
            const auto& devow = todev(lower);
            if (caps.count(lower)) {
                query = caps[lower];
            } else if (vows.count(devow)) {
                query = vows[devow];
            } else {
                query = "";
            }
        }
        return queries;
    }

private:
    string tolow(string word) {
        for (auto& c: word) {
            c = tolower(c);
        }
        return word;
    }

    string todev(string word) {
        static unordered_set<char> vowels{'a', 'e', 'i', 'o', 'u'};
        for (auto& c: word) {
            if (vowels.count(c)) {
                c = '*';
            }
        }
        return word;
    }
};

# Time:  O(n)
# Space: O(w)

class Solution(object):
    def spellchecker(self, wordlist, queries):
        """
        :type wordlist: List[str]
        :type queries: List[str]
        :rtype: List[str]
        """
        vowels = set(['a', 'e', 'i', 'o', 'u'])
        def todev(word):
            return "".join('*' if c.lower() in vowels else c.lower()
                           for c in word)

        words = set(wordlist)
        caps = {}
        vows = {}

        for word in wordlist:
            caps.setdefault(word.lower(), word)
            vows.setdefault(todev(word), word)

        def check(query):
            if query in words:
                return query
            lower = query.lower()
            if lower in caps:
                return caps[lower]
            devow = todev(lower)
            if devow in vows:
                return vows[devow]
            return ""
        return map(check, queries)
